INSERT INTO `laws_table` (`id`, `law_name`, `law_id`, `article_label`, `article_num`, `category`, `tags`, `summary`) VALUES
(1, '金融商品取引法', '323AC0000000025', '第29条', '29', '金融商品取引業者', '金融商品取引業者,登録,登録申請', '法令の条文の内容の要約をお願いします。\r\n①金融商品取引法の第29条\r\n\r\n9:57\r\n\r\n第29条の登録要件を確認し、基礎を構築した。\r\n第29条の登録要件を確認し、基礎を構築した。\r\n金融商品取引法 第29条の要約です。\r\n\r\n条文の趣旨\r\n第29条は、金融商品取引業を行おうとする者に対して、内閣総理大臣（実務上は金融庁長官への委任により金融庁）の登録を受けることを義務付ける規定です。\r\n\r\n内容のポイント\r\n\r\n登録義務\r\n　金融商品取引業（第一種金融商品取引業、第二種金融商品取引業、投資助言・代理業、投資運用業）に該当する行為を「業として」行おうとする者は、あらかじめ内閣総理大臣の登録を受けなければなりません。金融商品取引業に当たる業務を行うためには、当該業務について金融庁の登録を受けなければならないとされています。 \r\nKeiyaku Watch\r\n「金融商品取引業者」の定義\r\n　この登録を受けた者が、法律上「金融商品取引業者」と呼ばれます（法第2条第9項において、金融商品取引業者とは第29条の規定により内閣総理大臣の登録を受けた者をいう、と定義されています）。 \r\nHourei\r\n無登録営業の罰則\r\n　登録を受けずに金融商品取引業を行った場合には刑事罰の対象となります。無登録で金融商品取引業を行った者には5年以下の拘禁刑もしくは500万円以下の罰金が科され、または併科されるほか、法人・団体に対しても5億円以下の罰金が科されます。 \r\nKeiyaku Watch\r\n関連条文との関係\r\n\r\n第29条の2：登録申請の手続・記載事項\r\n第29条の4：登録拒否事由（財産的基礎、人的構成、反社会的勢力の排除など）\r\n第29条の4の2等：少額電子募集取扱業務など特例的な登録類型\r\nTK-GKスキームの私募ファンド運営との関係で言うと、御社の私募ファンド事業が「集団投資スキーム持分の自己募集・私募」や「投資運用（アセットマネジメント業務）」に該当する場合、これは第二種金融商品取引業や投資運用業として第29条の登録対象になり得る論点です（適格機関投資家等特例業務等の特例の適用可否も含め、実務上は個別の該当性判断が必要です）。'),
(2, '金融商品取引法', '323AC0000000025', '第34条', '34', '特定投資家', '特定投資家,告知,アマ,プロ成り', '第34条は、特定投資家制度（いわゆる「プロ・アマ制度」）に関する一連の規定（第34条～第34条の4等）の冒頭に置かれた、業者から特定投資家への告知義務を定めた条文です。\r\n内容\r\n\r\n金融商品取引業者等が、特定投資家（第2条第31項第4号に掲げる者＝一般投資家への移行が可能な類型の特定投資家、例：資本金5億円以上の株式会社など）から金融商品取引契約の申込みを受けた場合であって、\r\n\r\nその契約の種類について、過去にその特定投資家と契約を締結したことがないとき\r\n\r\nには、契約締結までに、その特定投資家に対し「一般投資家への移行の申出（第34条の2第1項）ができる旨」を告知しなければならない、という業者側の義務を規定しています。\r\n制度全体の中での意味\r\n\r\n金商法は投資家を「特定投資家（プロ）」と「一般投資家（アマ）」に区分し、特定投資家との取引については契約締結前交付書面の交付義務や適合性の原則など、情報格差是正を目的とする行為規制の一部を適用除外としています（第45条）。\r\n第34条はその大前提として、移行可能な特定投資家に対し「アマに戻れる権利があること」を知らせる手続的な義務を課すものです。\r\n関連条文：\r\n\r\n　- 第34条の2：特定投資家→一般投資家への移行手続\r\n\r\n　- 第34条の3：（特定投資家以外の）法人が特定投資家とみなされる場合（アマ→プロ移行）\r\n\r\n　- 第34条の4：個人が特定投資家とみなされる場合\r\n\r\n　- 第45条：特定投資家に対する行為規制の適用除外\r\n\r\n実務上のポイント\r\n\r\n御社の私募ファンド（TK-GKスキーム）の投資家が、例えば資本金5億円以上の法人など「移行可能な特定投資家」類型に該当する場合、契約締結前にこの告知義務が発生する点に留意が必要です。逆に、適格機関投資家など「移行不可の特定投資家」（第2条第31項第1号～第3号）にはこの告知義務は適用されません。'),
(3, '金融商品取引法', '323AC0000000025', '第2条', '2', '適格機関投資家・私募', '適格機関投資家,私募', '第2条は法律全体の「定義」規定であり、非常に長大な条文です。ご質問の「適格機関投資家」に関連する部分は、主に第3項（有価証券の募集・私募の定義）と第31項（特定投資家の定義）に登場します。\r\n1. 適格機関投資家の定義（第3項第1号）\r\n\r\n条文上は「有価証券に対する投資に係る専門的知識及び経験を有する者として内閣府令で定める者」とされており、具体的な範囲は法律本体ではなく、下位法令である**「金融商品取引法第二条に規定する定義に関する内閣府令」（定義府令）第10条**に委任されています。\r\n\r\n定義府令が定める主な該当者：\r\n\r\n金融商品取引業者（第一種金融商品取引業者・投資運用業者等）\r\n銀行、保険会社、信用金庫等の金融機関\r\n適格機関投資家等特例業務届出者\r\n有価証券残高10億円以上等の要件を満たし金融庁長官に届出を行った法人・個人 　など\r\n\r\n2. 私募制度における役割（第3項第1号：適格機関投資家私募）\r\n\r\n「有価証券の募集」に該当しない場合として、適格機関投資家のみを相手方として行う取得勧誘（＝適格機関投資家私募）が定義されています。これにより、適格機関投資家のみを対象とする勧誘は、多数の一般投資家向けの「募集」規制（有価証券届出書の提出義務等）が適用されず、機動的な資金調達・私募ファンド組成が可能になります。\r\n3. 特定投資家制度における位置づけ（第31項第1号）\r\n\r\n適格機関投資家は、「特定投資家」（いわゆるプロ投資家）のうち一般投資家への移行が認められない類型として位置づけられます（第34条・第34条の2の対象外）。特定投資家に対しては、契約締結前交付書面の交付義務や適合性の原則など、情報格差是正を目的とする行為規制の多くが適用除外となります（第45条）。\r\n実務上のポイント（TK-GKスキームとの関係）\r\n\r\n私募ファンドの持分（匿名組合出資持分等）の勧誘を行う際、相手方が適格機関投資家のみであれば「適格機関投資家私募」として募集規制の適用が緩和されます。また、「適格機関投資家等特例業務」（第63条）の届出制度も、適格機関投資家を出資者に含めることを要件の一つとしており、御社のファンド組成スキームの法的構成を検討する際の重要な起点となる概念です。'),
(4, '金融商品取引法', '323AC0000000025', '第41条', '41', '投資助言業務', '投資助言,善良な管理者,顧客,', '金融商品取引法 第41条（投資助言業に関する特則：忠実義務・善管注意義務）の要約です。\r\n位置づけ\r\n\r\n第41条は、法第2章の2「金融商品取引業者等に関する行為規制」のうち、投資助言業務に特有の規制を定める款（第41条～第41条の2等）の冒頭に置かれた条文です。\r\n内容\r\n\r\n金融商品取引業者等（投資助言業を行う者）は、その行う投資助言業務に関し、顧客に対して忠実義務及び善管注意義務を負う旨を定めています。具体的には：\r\n\r\n第1項（忠実義務）：投資助言業務に関して、顧客に対し誠実かつ公正に業務を遂行しなければならない。\r\n第2項（善管注意義務）：投資助言業務に関して、善良な管理者の注意をもって業務を行わなければならない。\r\n\r\n制度上の位置づけ\r\n\r\nこの忠実義務・善管注意義務は、投資助言業者が顧客の投資判断に直接影響を与える立場にあることを踏まえ、旧証券取引法・旧投資顧問業法から継承された投資助言業固有の一般的行為規範です。\r\n具体的な禁止行為（利益相反的な助言、根拠のない助言、損失補てん等）は、続く**第41条の2（禁止行為）**でより詳細に列挙されています。\r\n第41条の5では、投資助言業務に関連した顧客への金銭・有価証券の貸付け等が原則禁止されています。\r\n\r\n関連条文との関係\r\n条文内容第2条第8項第11号投資助言業務（投資顧問契約に基づく助言）の定義第41条忠実義務・善管注意義務（一般規範）第41条の2禁止行為（利益相反、無根拠助言、損失補てん等の個別列挙）第41条の5金銭・有価証券の貸付け等の禁止第40条適合性の原則（業者共通の行為規制）\r\n実務上のポイント\r\n\r\n御社が検討されているAI活用のコンプライアンス支援事業が、単なる法令情報提供にとどまらず、具体的な投資判断（銘柄・タイミング等）への助言に踏み込む場合、この投資助言業の登録要否（第29条）や第41条の忠実義務が問題となり得ます。逆に、法令情報の検索・整理にとどまるサービス設計（現在プロトタイプで想定されている範囲）であれば、投資助言業には該当しない可能性が高いと考えられます。\r\n'),
(5, '金融商品取引法', '323AC0000000025', '第42条', '42', '投資運用業', '投資運用,権利者,忠実義務,善管注意義務,損失補填', '第42条は、投資運用業（ファンド運用・投資一任契約等）に固有の行為規制を定める款の冒頭条文です。TK-GKスキームのアセットマネジメント業務に直接関わる、実務上非常に重要な条文です。\r\n内容\r\n第1項（忠実義務）\r\n\r\n金融商品取引業者等は権利者のため忠実に投資運用業を行わなければならない。ここでいう「権利者」は業務の種類ごとに定義されており、投資一任契約であれば契約の相手方、集団投資スキーム（匿名組合等）であればその持分を有する出資者が該当します。 Thoz\r\n第2項（善管注意義務）\r\n\r\n金融商品取引業者等は、権利者に対し善良な管理者の注意をもって投資運用業を行わなければならない、と定めています。\r\n趣旨\r\n\r\n忠実義務・善管注意義務は取締役が会社に対して負う責任と同等であり、専門的知識を持つ投資運用業者として高度の注意を払い、権利者の利益のために忠実に業務を行うことを求めるものです。金融庁の監督指針でも、投資者の資産運用において重要な役割を担う金融商品取引業者は運用を委託した投資者に対して受託者責任を負っており、忠実義務・善管注意義務・分別管理義務等が課されているとされています。 Taurus-financialFinancial Services Agency\r\n具体化する規定：第42条の2（禁止行為）\r\n\r\n第42条の忠実義務・善管注意義務を具体的なルールベースの禁止行為として明文化したのが第42条の2です。主な禁止行為：\r\n\r\n自己取引（自己・役員等との取引を内容とする運用）\r\n運用財産相互間取引\r\n取引価格等の変動を利用した、正当な根拠のない取引\r\n通常と異なる不利な条件での取引\r\n損失補塡・利益追加のための財産上の利益提供\r\n\r\n第42条の3（運用権限の委託）との関係\r\n\r\n投資運用業者が運用権限を第三者に委託する場合、忠実義務・善管注意義務（42条）及び行為準則（42条の2）の規定は委託先まで直接適用されます。また委託元と委託先は、権利者に対する忠実義務・善管注意義務に基づき再委託先の選任・監督についても責任を負うとされています。なお、投資運用業者は運用権限の全部を委託することは原則禁止されています（第42条の3第2項）。 JPX + 2\r\n実務上のポイント（現在進行中の案件との関係）\r\n\r\n現在対応されている物流施設ファンドの計算誤りの件は、まさにこの第42条の善管注意義務の観点から評価されうる論点です。\r\n\r\nAM会社側の計算誤りが「専門家として通常求められる注意」を欠いていたかどうかが善管注意義務違反の有無の判断軸になります。\r\n過去の行政処分例でも、ファンド契約書等に記載された投資対象と関係のない運用や計理・運用上のミスが忠実義務・善管注意義務違反として問題視された事例があります。 Taurus-financial\r\nAM報酬の調整・会計是正・早期売却等の対応方針を検討される際、「権利者（出資者）の利益を害さない形で、かつ善管注意義務に照らして合理的な説明ができる対応か」という視点は、外部専門家との協議において重要な軸になり得ます。\r\n'),
(6, '金融商品取引法', '323AC0000000025', '第2条第8項', '2-8', '金融商品取引業の行為類型の全体像', '', '第2条第8項（金融商品取引業の定義）\r\n内容\r\n\r\n「金融商品取引業」とは、第8項各号に掲げる行為（有価証券の売買、募集・私募の取扱い、有価証券の引受け、集団投資スキーム持分の自己募集・自己運用、投資助言、投資一任、デリバティブ取引等）のいずれかを業として行うことをいう、と定義する条文です。「業として」とは対公衆性・反復継続性を要件とし、実際に行われている場合だけでなく想定される場合も含まれると解されています。\r\n業態区分（第28条で規定）\r\n\r\n第一種金融商品取引業（有価証券関連業等）\r\n第二種金融商品取引業（集団投資スキーム持分の自己募集・自己私募等）＝TK-GKスキームの匿名組合出資持分募集はここに該当\r\n投資助言・代理業\r\n投資運用業（自己運用＝AM業務）＝TK-GKスキームの運用はここに該当\r\n自己募集・自己私募が金融商品取引業として規定されている点（第7号）が、証券取引法時代からの大きな変更点で、TK-GKスキームの実務上の出発点となる規定です。'),
(7, '金融商品取引法', '323AC0000000025', '第40条', '40', '適合性の原則等', '顧客,特定投資家,プロ投資家,知識,経験,財産,目的', ' 第40条（適合性の原則等）\r\n内容\r\n\r\n金融商品取引業者等は、業務運営の状況が次のいずれかに該当しないように業務を行わなければならないと規定：\r\n\r\n第1号（適合性の原則）：金融商品取引行為について、顧客の知識・経験・財産の状況・契約締結の目的に照らして不適当な勧誘を行い、投資者保護に欠けることとなっている、又はそのおそれがあること\r\n第2号：顧客情報の適正な取扱いを確保する措置を講じていない等、投資者保護に支障を生ずるおそれがある状況\r\n\r\n趣旨\r\n\r\n最判平成17年7月14日の考え方を踏まえ、勧誘段階での投資家属性に応じた適合性を求める規定です。特定投資家（プロ投資家）にはこの規定は適用されません（第45条）。'),
(8, '金融商品取引法', '323AC0000000025', '第42条の2', '42-2', '投資運用業の禁止行為', '投資運用,禁止行為,自己取引,相互間取引,損失補填,適用除外', '第42条の2（投資運用業の禁止行為）\r\n内容\r\n\r\n第42条の忠実義務・善管注意義務を具体化した、ルールベースの禁止行為規定です。主な禁止行為：\r\n\r\n自己取引（自己又はその取締役・執行役との取引を内容とした運用）\r\n運用財産相互間取引\r\n正当な根拠のない、価格変動を利用した取引\r\n通常と異なる不利な条件での取引\r\n損失補塡・利益追加のための財産上の利益提供\r\n\r\n適用除外\r\n\r\n自己取引・運用財産相互間取引にはそれぞれ金商業等府令128条・129条で合理的な価格算出等を要件とする適用除外規定があり、マスター・フィーダー構造のファンドについても一定条件下で該当しないとするパブコメ回答があります。'),
(9, '金融商品取引法', '323AC0000000025', '第52条', '52', '金融商品取引業者に対する監督上の処分', '行政処分,業務改善命令,業務停止,登録取消,解任命令,忠実義務,全巻注意義務', '第52条（金融商品取引業者に対する監督上の処分）\r\n内容\r\n\r\n内閣総理大臣（実務上は金融庁・財務局）は、金融商品取引業者が次のいずれかに該当する場合、登録取消・認可取消・6月以内の業務の全部又は一部停止を命ずることができます。主な事由：\r\n\r\n不正の手段による登録取得\r\n法令又は行政処分への違反\r\n支払不能に陥るおそれ\r\n投資助言・代理業又は投資運用業の運営に関し、投資者の利益を害する事実があるとき（第9号）\r\n不正・著しく不当な行為で情状が特に重いとき\r\n\r\n関連\r\n\r\n第51条（業務改善命令）はより軽い処分として位置づけられ、実務上はまず業務改善命令、悪質な場合に業務停止・登録取消に進むケースが多く見られます。役員の解任命令（第2項）も規定されています。\r\n実務上のポイント：ファンドの計算誤り等が発生した場合、外部専門家と協議の上で誠実な是正対応を取ることは、第52条第9号（投資者利益を害する事実）や忠実義務・善管注意義務違反として問題視されるリスクを抑える観点からも重要です。'),
(10, '金融商品取引法', '323AC0000000025', '第63条', '63', '適格機関投資家等特例業務', '適格機関投資家,私募,第二種金融商品取引業,投資運用業,登録義務,簡易届出', '第63条（適格機関投資家等特例業務）\r\n内容\r\n\r\n集団投資スキーム持分（匿名組合出資持分等）の自己募集・自己私募（第2条第8項第7号）や自己運用（第15号）について、以下の要件を満たす場合、第二種金融商品取引業・投資運用業の登録義務が免除され、簡易な届出のみで業務を行うことができる制度です（第63条第2項）。\r\n主な要件（施行令第17条の12）\r\n\r\n出資者の全てが適格機関投資家である場合、または\r\n出資者に1人以上の適格機関投資家と、49人以下の一定の投資判断能力を有する者が含まれる場合\r\n\r\n行為規制の適用関係\r\n\r\n届出のみで足りる一方、以下の規制は適格機関投資家等特例業務にも適用されます（第63条第11項）：\r\n\r\n特定投資家への告知義務等（第34条～第34条の5）\r\n顧客に対する誠実義務（第36条第1項）\r\n虚偽告知の禁止、損失補塡の禁止 等\r\n\r\n実務上のポイント\r\n\r\n御社のTK-GKスキームが、適格機関投資家＋49名以下の適格投資家のみを出資者とする設計であれば、この特例業務の届出により、フルライセンス（第二種金商業・投資運用業）を取得せずに事業を運営できる可能性があります。ただし出資者の範囲・人数管理、事業報告書の作成・提出（第63条の4）、公衆縦覧等の継続的な義務があるため、ガバナンス設計上の留意が必要です。');

